import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.authentication.logout.SecurityContextLogoutHandler;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

@Controller
public class LogoutController {

    private final SecurityContextLogoutHandler logoutHandler = new SecurityContextLogoutHandler();

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null) {
            this.logoutHandler.logout(request, response, auth);
        }

        String nextUrl = request.getParameter("next");
        if (nextUrl != null && !nextUrl.trim().isEmpty()) {
            // WARNING: Allowing unvalidated 'next' parameter can lead to open redirect vulnerabilities.
            // For production systems, validate 'nextUrl' against a whitelist of allowed domains or paths.
            response.sendRedirect(nextUrl);
        } else {
            // Redirect to a default page if 'next' parameter is missing or empty
            response.sendRedirect("/login?loggedOut"); // Example: redirect to a login page
        }
    }
}